public class Calculator {
  public int add(int a, int b) {
    int result = a + b;
    return result;
  }

  public double add(double a, double b) {
    double result = a + b;
    return result;
  }

  public String add(String a, String b) {
    String result = a + b;
    return result;
  }

  public static void main(String[] args) {
    Calculator calc = new Calculator();
    int sum1 = calc.add(5, 3);
    double sum2 = calc.add(2.5, 3.7);
    String concat = calc.add("Salam, ", "dünya!");
    System.out.println("İki ədədin cəmi: " + sum1);
    System.out.println("İki onluq ədədin cəmi: " + sum2);
    System.out.println("Sətir birləşməsi: " + concat);
  }
}
// Çıxış:
// İki ədədin cəmi: 8
// İki onluq ədədin cəmi: 6.2
// Sətir birləşməsi: Salam, dünya!

public class Printer {
  public void print(String message) {
    System.out.println("Mesaj: " + message);
  }

  public void print(int number) {
    System.out.println("Ədəd: " + number);
  }

  public void print(String message, int number) {
    System.out.println("Mesaj və ədəd: " + message + ", " + number);
  }

  public static void main(String[] args) {
    Printer printer = new Printer();
    printer.print("Salam!");
    printer.print(42);
    printer.print("Test", 100);
  }
}
// Çıxış:
// Mesaj: Salam!
// Ədəd: 42
// Mesaj və ədəd: Test, 100

