public class Calculator {
  public int add(int a, int b) {
    int result = a + b;
    return result;
  }

  public double add(double a, double b) {
    double result = a + b;
    return result;
  }

  public String add(String a, String b) {
    String result = a + b;
    return result;
  }

  public static void main(String[] args) {
    Calculator calc = new Calculator();
    int sum1 = calc.add(5, 3);
    double sum2 = calc.add(2.5, 3.7);
    String concat = calc.add("Привет, ", "мир!");
    System.out.println("Сумма двух целых чисел: " + sum1);
    System.out.println("Сумма двух дробных чисел: " + sum2);
    System.out.println("Конкатенация строк: " + concat);
  }
}
// Вывод:
// Сумма двух целых чисел: 8
// Сумма двух дробных чисел: 6.2
// Конкатенация строк: Привет, мир!

public class Printer {
  public void print(String message) {
    System.out.println("Сообщение: " + message);
  }

  public void print(int number) {
    System.out.println("Число: " + number);
  }

  public void print(String message, int number) {
    System.out.println("Сообщение и число: " + message + ", " + number);
  }

  public static void main(String[] args) {
    Printer printer = new Printer();
    printer.print("Привет!");
    printer.print(42);
    printer.print("Тест", 100);
  }
}
// Вывод:
// Сообщение: Привет!
// Число: 42
// Сообщение и число: Тест, 100

